from django.utils.text import slugify


def _build_unique_slug(dataset_tag_model, tag_name):
    base_slug = slugify(tag_name, allow_unicode=True)[:100] or "tag"
    candidate = base_slug
    counter = 2

    while dataset_tag_model.objects.filter(slug=candidate).exists():
        suffix = f"-{counter}"
        candidate = f"{base_slug[: 100 - len(suffix)]}{suffix}"
        counter += 1

    return candidate


def migrate_dataset_json_tags(apps, schema_editor):
    Dataset = apps.get_model('catalog', 'Dataset')
    DatasetTag = apps.get_model('catalog', 'DatasetTag')
    DatasetTaggedItem = apps.get_model('catalog', 'DatasetTaggedItem')

    for dataset in Dataset.objects.all().iterator():
        tag_names = dataset.tags if isinstance(dataset.tags, list) else []
        for tag_name in tag_names:
            normalized_name = str(tag_name).strip()
            if not normalized_name:
                continue

            dataset_tag = DatasetTag.objects.filter(name=normalized_name).first()
            if dataset_tag is None:
                dataset_tag = DatasetTag.objects.create(
                    name=normalized_name,
                    slug=_build_unique_slug(DatasetTag, normalized_name),
                )

            DatasetTaggedItem.objects.get_or_create(
                content_object_id=dataset.pk,
                tag_id=dataset_tag.pk,
            )


def reverse_dataset_json_tags(apps, schema_editor):
    Dataset = apps.get_model('catalog', 'Dataset')
    DatasetTaggedItem = apps.get_model('catalog', 'DatasetTaggedItem')

    dataset_tags = {}
    for tagged_item in DatasetTaggedItem.objects.select_related('tag').all().iterator():
        dataset_tags.setdefault(tagged_item.content_object_id, []).append(tagged_item.tag.name)

    for dataset in Dataset.objects.all().iterator():
        dataset.tags = dataset_tags.get(dataset.pk, [])
        dataset.save(update_fields=['tags'])


